/* =========================================================================
   BUBBLE GHOST — Le Souffle Fantôme
   Jeu type "Bubble Ghost" en HTML5 Canvas, rendu cartoon procédural.
   Aucune dépendance, aucun asset externe — tout est dessiné au code.
   ========================================================================= */

const canvas = document.getElementById('game');
const ctx = canvas.getContext('2d');

// Monde logique fixe (mis à l'échelle pour remplir l'écran).
const W = 1280, H = 720;

/* ----------------------------- Mise à l'échelle ----------------------------- */
let scale = 1, viewX = 0, viewY = 0;
function resize() {
  const ww = window.innerWidth, wh = window.innerHeight;
  scale = Math.min(ww / W, wh / H);
  canvas.width = Math.round(W * scale);
  canvas.height = Math.round(H * scale);
  viewX = (ww - canvas.width) / 2;
  viewY = (wh - canvas.height) / 2;
}
window.addEventListener('resize', resize);
resize();

/* --------------------------------- Entrées --------------------------------- */
const keys = {};
let mouse = { x: W / 2, y: H / 2, down: false, moved: false };

function toWorld(clientX, clientY) {
  const r = canvas.getBoundingClientRect();
  return { x: (clientX - r.left) / scale, y: (clientY - r.top) / scale };
}
addEventListener('keydown', e => {
  keys[e.code] = true;
  if (e.code === 'Space') e.preventDefault();
});
addEventListener('keyup', e => { keys[e.code] = false; });
canvas.addEventListener('mousemove', e => { const p = toWorld(e.clientX, e.clientY); mouse.x = p.x; mouse.y = p.y; mouse.moved = true; });
canvas.addEventListener('mousedown', () => mouse.down = true);
addEventListener('mouseup', () => mouse.down = false);

/* ------------------------- Joysticks tactiles (mobile) --------------------- */
const STICK_MAX = 80;
const sticks = {
  move: { cx: 120, cy: H - 140, r: 100, kx: 0, ky: 0, id: null },   // gauche : déplacer
};
// côté droit : boutons tourner ◄ / ► + souffler (coords écran)
const btns = {
  rotL: { cx: 980, cy: 650, r: 52, id: null, t: 0 },   // tourner ◄ (anti-horaire)
  rotR: { cx: 1100, cy: 650, r: 52, id: null, t: 0 },  // tourner ► (horaire)
  blow: { cx: 1200, cy: 555, r: 62, id: null },        // souffler
};
function rotateStep(dir) {                              // tourne d'un cran de 45° (et accroche la grille)
  const step = Math.PI / 4;
  ghost.angle = (Math.round(ghost.angle / step) + dir) * step;
}
function btnAt(px, py) {
  for (const k of ['rotL', 'rotR', 'blow']) {
    const b = btns[k];
    if (Math.hypot(px - b.cx, py - b.cy) <= b.r * 1.18) return k;
  }
  return null;
}
canvas.addEventListener('pointerdown', e => {
  if (state !== GS.PLAY) return;
  const p = toWorld(e.clientX, e.clientY);
  const bk = btnAt(p.x, p.y);
  if (bk && btns[bk].id === null) {                     // un bouton tactile
    btns[bk].id = e.pointerId; btns[bk].t = 0;
    if (bk === 'rotL') rotateStep(-1); else if (bk === 'rotR') rotateStep(1);   // appui = un cran de 45°
    if (canvas.setPointerCapture) try { canvas.setPointerCapture(e.pointerId); } catch (x) {}
    e.preventDefault(); return;
  }
  const s = sticks.move;                                // sinon : joystick de déplacement
  if (s.id !== null) return;
  s.id = e.pointerId;
  let dx = p.x - s.cx, dy = p.y - s.cy, d = Math.hypot(dx, dy);
  if (d > STICK_MAX) { dx = dx / d * STICK_MAX; dy = dy / d * STICK_MAX; }
  s.kx = dx; s.ky = dy;
  if (canvas.setPointerCapture) try { canvas.setPointerCapture(e.pointerId); } catch (x) {}
  e.preventDefault();
});
canvas.addEventListener('pointermove', e => {
  if (state !== GS.PLAY) return;
  const s = sticks.move;
  if (s.id === e.pointerId) {
    const p = toWorld(e.clientX, e.clientY);
    let dx = p.x - s.cx, dy = p.y - s.cy, d = Math.hypot(dx, dy);
    if (d > STICK_MAX) { dx = dx / d * STICK_MAX; dy = dy / d * STICK_MAX; }
    s.kx = dx; s.ky = dy;
  }
});
function releaseStick(e) {
  if (sticks.move.id === e.pointerId) { sticks.move.id = null; sticks.move.kx = 0; sticks.move.ky = 0; }
  for (const k of ['rotL', 'rotR', 'blow']) if (btns[k].id === e.pointerId) btns[k].id = null;
}
canvas.addEventListener('pointerup', releaseStick);
canvas.addEventListener('pointercancel', releaseStick);

const isBlowing = () => keys['Space'] || mouse.down || btns.blow.id !== null;

