const BRICK_SIZE = 80;   // toutes les briques à la même taille (carré) pour s'aligner
// Snap DOUX façon Photoshop : se cale sur les bords/centre d'une brique voisine (tolérance 8 px),
// sur chaque axe indépendamment. Renvoie la position + si un axe est aligné (pour tracer le guide).
function brickSnap(px, py, self) {
  const L = LEVELS[levelIndex], s = BRICK_SIZE, tol = 8;
  let bx = null, by = null, bxd = tol + 1, byd = tol + 1;
  if (L.props) for (const q of L.props) {
    if (q === self || q.kind !== 'brick') continue;
    for (const t of [q.x, q.x - s, q.x + s]) { const d = Math.abs(px - t); if (d <= tol && d < bxd) { bxd = d; bx = t; } }
    for (const t of [q.y, q.y - s, q.y + s]) { const d = Math.abs(py - t); if (d <= tol && d < byd) { byd = d; by = t; } }
  }
  return { x: Math.round(bx != null ? bx : px), y: Math.round(by != null ? by : py), snapX: bx != null, snapY: by != null };
}
// Aimantation des dalles de mur : se collent bord à bord (gauche/droite) + même hauteur, aux murs voisins.
function murSnap(px, py, self) {
  const L = LEVELS[levelIndex], tol = 12;
  const sw = self ? self.w : 320;
  let sh = self ? self.h : 90;
  if (!self) { const im = images['assets/mur1.png']; if (im) sh = 320 * im.naturalHeight / im.naturalWidth; }
  let nx = px, ny = py, sx = false, sy = false, bxd = tol + 1, byd = tol + 1;
  if (L.props) for (const q of L.props) {
    if (q === self || q.kind !== 'mur') continue;
    for (const t of [q.x, q.x - (q.w / 2 + sw / 2), q.x + (q.w / 2 + sw / 2)]) { const d = Math.abs(px - t); if (d <= tol && d < bxd) { bxd = d; nx = t; sx = true; } }
    for (const t of [q.y, q.y - (q.h / 2 + sh / 2), q.y + (q.h / 2 + sh / 2)]) { const d = Math.abs(py - t); if (d <= tol && d < byd) { byd = d; ny = t; sy = true; } }
  }
  return { x: Math.round(nx), y: Math.round(ny), snapX: sx, snapY: sy };
}
// Magnétisme RELATIF : colle la brique au bord de la brique voisine la plus proche (dans tous les sens).
function snapBrickPos(x, y, selfIdx) {
  const L = LEVELS[levelIndex];
  let best = null, bd = Infinity;
  if (L.props) for (let i = 0; i < L.props.length; i++) {
    if (i === selfIdx) continue;
    const q = L.props[i]; if (q.kind !== 'brick') continue;
    const d = dist2(x, y, q.x, q.y); if (d < bd) { bd = d; best = q; }
  }
  const step = BRICK_SIZE;
  if (best && bd < (step * 1.7) * (step * 1.7)) {       // une brique voisine est proche → on s'y colle
    const dx = x - best.x, dy = y - best.y;
    if (Math.abs(dx) >= Math.abs(dy)) return { x: best.x + (dx >= 0 ? step : -step), y: best.y };
    return { x: best.x, y: best.y + (dy >= 0 ? step : -step) };
  }
  return { x: snapBrick(x), y: snapBrick(y) };           // sinon : grille absolue
}
