function spawnDebris(cx, topY, botY, w) {
  const n = Math.max(4, Math.min(9, Math.round(w / 16)));
  for (let i = 0; i < n; i++) {
    debris.push({
      img: DEBRIS_IMGS[Math.floor(rand(0, DEBRIS_IMGS.length))],
      x: cx + rand(-w * 0.75, w * 0.75), y: topY + rand(-6, 10),
      vx: rand(-35, 35), vy: rand(0, 40),
      rot: rand(0, 6.28), rotS: rand(-7, 7),
      size: rand(14, 26), delay: rand(0, 0.5),           // tombe en décalé (pas tous d'un coup)
      grounded: false, restT: 0, rest: rand(2.0, 3.5),
    });
  }
}
// Trouve la surface (haut de brique/mur, ou caillou déjà posé, sinon bas du monde) sous un caillou
function debrisGround(d) {
  let gy = worldH - 4;
  const L = LEVELS[levelIndex];
  if (L.props) for (const q of L.props) {
    if (q.kind !== 'brick' && q.kind !== 'mur') continue;
    const topY = q.y - q.h / 2;
    if (d.x > q.x - q.w * 0.46 && d.x < q.x + q.w * 0.46 && topY >= d.y - 4 && topY < gy) gy = topY;
  }
  for (const o of debris) {                              // empilement sur les cailloux déjà posés
    if (o === d || !o.grounded) continue;
    if (Math.abs(d.x - o.x) < (d.size + o.size) * 0.38) { const t = o.y - o.size * 0.42; if (t >= d.y - 4 && t < gy) gy = t; }
  }
  return gy;
}
function updateDebris(dt) {
  for (let i = debris.length - 1; i >= 0; i--) {
    const d = debris[i];
    if (d.delay > 0) { d.delay -= dt; continue; }        // pas encore tombé
    if (d.grounded) {                                    // posé : reste un moment puis s'efface
      d.restT += dt;
      if (d.restT > d.rest + 0.6) debris.splice(i, 1);
      continue;
    }
    d.vy += 760 * dt; d.x += d.vx * dt; d.y += d.vy * dt; d.vx *= 0.99; d.rot += d.rotS * dt;
    const gy = debrisGround(d);
    if (d.y + d.size * 0.42 >= gy) {                      // atterrit sur la brique / l'empilement
      d.y = gy - d.size * 0.42; d.grounded = true; d.vx = 0; d.vy = 0; d.rotS = 0;
      for (let k = 0; k < 2; k++) smokePuffs.push({ x: d.x + rand(-4, 4), y: d.y + d.size * 0.4, vx: rand(-18, 18), vy: rand(-22, -4), t: 0, life: rand(0.3, 0.55), r: rand(5, 10) });
    }
  }
}
function drawDebris() {
  for (const d of debris) {
    if (d.delay > 0) continue;
    const im = images[d.img]; if (!im) continue;
    const w = d.size, h = w * im.naturalHeight / im.naturalWidth;
    const a = d.grounded && d.restT > d.rest ? Math.max(0, 1 - (d.restT - d.rest) / 0.6) : 1;
    ctx.save(); ctx.globalAlpha = a; ctx.translate(d.x, d.y); ctx.rotate(d.rot);
    ctx.drawImage(im, -w / 2, -h / 2, w, h);
    ctx.restore();
  }
}
let smokePuffs = [];  // fumée/poussière au claquement des pièges-presse
function spawnSmoke(cx, cy, w) {
  // style « nuage volumineux » : beaucoup de gros puffs cotonneux (dégradé radial)
  const n = Math.max(12, Math.min(22, Math.round(w / 7)));
  for (let i = 0; i < n; i++) smokePuffs.push({ x: cx + rand(-w * 0.6, w * 0.6), y: cy + rand(-14, 14), vx: rand(-40, 40), vy: rand(-40, -4), t: 0, life: rand(0.7, 1.3), r: rand(18, 36) });
}
function updateSmoke(dt) {
  for (let i = smokePuffs.length - 1; i >= 0; i--) {
    const s = smokePuffs[i];
    s.t += dt; s.x += s.vx * dt; s.y += s.vy * dt; s.vx *= 0.9; s.vy *= 0.9;
    if (s.t >= s.life) smokePuffs.splice(i, 1);
  }
}
function drawSmoke() {
  for (const s of smokePuffs) {
    const k = s.t / s.life, a = 0.4 * (1 - k), rr = s.r * (1 + k * 1.4);
    const g = ctx.createRadialGradient(s.x, s.y, 1, s.x, s.y, rr);
    g.addColorStop(0, `rgba(225,228,236,${a})`); g.addColorStop(1, 'rgba(225,228,236,0)');
    ctx.fillStyle = g; ctx.beginPath(); ctx.arc(s.x, s.y, rr, 0, 7); ctx.fill();
  }
}
