function pickLeaf() { return LEAF_FALL[(Math.random() * LEAF_FALL.length) | 0]; }
function initLeaves() {
  const ww = worldW || W, wh = worldH || H;
  const n = Math.max(5, Math.min(14, Math.round(ww / 260)));   // densité douce, selon la largeur du monde
  leaves = [];
  for (let i = 0; i < n; i++) {
    leaves.push({
      x: rand(0, ww), y: rand(-wh, wh),
      vy: rand(18, 42), swayA: rand(14, 40), swayS: rand(0.5, 1.3), phase: rand(0, 6.28),
      rot: rand(0, 6.28), rotS: rand(-1, 1),
      img: pickLeaf(), sc: rand(0.13, 0.24), a: rand(0.5, 0.9),
    });
  }
}
function updateLeaves(dt) {
  const ww = worldW || W, wh = worldH || H;
  for (const l of leaves) {
    l.y += l.vy * dt;
    l.phase += l.swayS * dt;
    l.rot += l.rotS * dt;
    if (l.y > wh + 50) { l.y = rand(-100, -20); l.x = rand(0, ww); l.img = pickLeaf(); }
  }
}
function drawLeaves() {
  for (const l of leaves) {
    const im = images[l.img]; if (!im || !im.naturalWidth) continue;
    const x = l.x + Math.sin(l.phase) * l.swayA;
    const w = im.naturalWidth * l.sc, h = im.naturalHeight * l.sc;
    ctx.save();
    ctx.globalAlpha = l.a;
    ctx.translate(x, l.y);
    ctx.rotate(l.rot + Math.sin(l.phase) * 0.3);     // tangue en tombant
    ctx.drawImage(im, -w / 2, -h / 2, w, h);
    ctx.restore();
  }
  ctx.globalAlpha = 1;
}

